/**
 * Shared type utilities for @munesoft/objx
 */
/** Any plain object */
export type PlainObject = Record<string | number, unknown>;
/** Options for deep get */
export interface GetOptions {
    /** If true, throw instead of returning fallback on missing path */
    strict?: boolean;
}
/** Options for deep set */
export interface SetOptions {
    /** Return a new object instead of mutating the original */
    immutable?: boolean;
}
/** Array merge strategies for deep merge */
export type ArrayStrategy = "replace" | "concat" | "merge";
/** Options for deep merge */
export interface MergeOptions {
    /** How arrays are handled. Default: "replace" */
    arrays?: ArrayStrategy;
    /** Mutate the first object instead of creating a new one. Default: false */
    mutate?: boolean;
}
/** Returns true if value is a plain (non-null, non-array) object */
export declare function isPlainObject(value: unknown): value is PlainObject;
